  ('aboriginal-3df1c47f-moex-00028', 'aboriginal-3df1c47f', 'aboriginal-3df1c47f-moex-113-20e3c385', 'sub-aboriginal-3df1c47f-03', NULL, 'essay', '依據污染物種類說明農地土壤整治復育方法。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:26+00:00", "source_pdf_sha1": "a83e9edb1ebf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "411", "s": "1404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土壤學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業技術"}'::jsonb, NULL),
